sql:
SELECT date, sea_of_okhotsk
FROM sea_ice_measurements
ORDER BY date ASC;

SELECT AVG(sea_of_okhotsk) AS average_sea_ice_extent
FROM sea_ice_measurements
WHERE date = '1983-03-20';

SELECT date, sea_of_okhotsk, bering_sea
FROM sea_ice_measurements
WHERE version > 1;

external_knowledge:
- NASA and University of Alaska are institutions; 
- A top quality score refers to the highest quality score for a measurement;
- January 1, 2023, is the start date for the validation period.

sql:
SELECT AVG(barents_sea) AS avg_barents_sea_ice
FROM sea_ice_measurements
WHERE data_source_id = (SELECT source_id FROM data_sources WHERE source_name = 'ICESat-2');

SELECT measurement_id
FROM sea_ice_measurements
WHERE central_arctic = (SELECT MAX(central_arctic) FROM sea_ice_measurements);

SELECT SUM(sea_of_okhotsk + bering_sea + hudson_bay + baffin_bay + east_greenland_sea + barents_sea + kara_sea + laptev_sea + east_siberian_sea + chukchi_sea + beaufort_sea + canadian_archipelago + central_arctic) AS total_sea_ice_extent
FROM sea_ice_measurements
WHERE measurement_id = 0;

SELECT sea_of_okhotsk
FROM sea_ice_measurements
WHERE version = (SELECT MAX(version) FROM sea_ice_measurements);
